import java.util.concurrent.ConcurrentHashMap;

@WebService(serviceName = "PaymentProcessingService")
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT)
public class PaymentProcessingService {
    
    private static final Map<String, PaymentTransaction> transactions = new ConcurrentHashMap<>();
    
    @WebMethod
    public PaymentResponse processPayment(
            @WebParam(name = "cardNumber") String cardNumber,
            @WebParam(name = "amount") double amount,
            @WebParam(name = "currency") String currency,
            @WebParam(name = "merchantId") String merchantId) {
        
        PaymentResponse response = new PaymentResponse();
        
        try {
            String transactionId = UUID.randomUUID().toString();
            PaymentTransaction transaction = new PaymentTransaction();
            transaction.setTransactionId(transactionId);
            transaction.setCardNumber(maskCardNumber(cardNumber));
            transaction.setAmount(amount);
            transaction.setCurrency(currency);
            transaction.setMerchantId(merchantId);
            transaction.setTimestamp(new Date());
            transaction.setStatus("APPROVED");
            
            transactions.put(transactionId, transaction);
            
            response.setTransactionId(transactionId);
            response.setStatus("APPROVED");
            response.setMessage("Payment processed successfully");
            response.setAuthorizationCode(generateAuthCode());
            
        } catch (Exception e) {
            response.setStatus("DECLINED");
            response.setMessage("Payment processing failed: " + e.getMessage());
        }
        
        return response;
    }
    
    @WebMethod
    public TransactionStatus getTransactionStatus(@WebParam(name = "transactionId") String transactionId) {
        TransactionStatus status = new TransactionStatus();
        PaymentTransaction transaction = transactions.get(transactionId);
        
        if (transaction != null) {
            status.setTransactionId(transactionId);
            status.setStatus(transaction.getStatus());
            status.setAmount(transaction.getAmount());
            status.setCurrency(transaction.getCurrency());
            status.setTimestamp(transaction.getTimestamp());
        } else {
            status.setStatus("NOT_FOUND");
        }
        
        return status;
    }
    
    private String maskCardNumber(String cardNumber) {
        if (cardNumber == null || cardNumber.length() < 4) {
            return "****";
        }
        return "****-****-****-" + cardNumber.substring(cardNumber.length() - 4);
    }
    
    private String generateAuthCode() {
        return "AUTH" + System.currentTimeMillis() % 1000000;
    }
    
    public static void main(String[] args) {
        Endpoint endpoint = Endpoint.create(new PaymentProcessingService());
        
        List<javax.xml.ws.handler.Handler> handlerChain = new ArrayList<>();
        handlerChain.add(new TimestampSecurityHandler());
        endpoint.getBinding().setHandlerChain(handlerChain);
        
        endpoint.publish("http://localhost:8080/payment");
        System.out.println("Payment Processing Service started at http://localhost:8080/payment");
    }
}

