class TimestampSecurityHandler implements SOAPHandler<SOAPMessageContext> {
    
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final long TIMESTAMP_VALIDITY_MS = 300000;
    
    private static final Set<String> processedMessageIds = Collections.newSetFromMap(new ConcurrentHashMap<>());
    
    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        
        if (outbound) {
            return handleOutbound(context);
        } else {
            return handleInbound(context);
        }
    }
    
    private boolean handleOutbound(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();
            
            if (header == null) {
                header = envelope.addHeader();
            }
            
            SOAPElement security = header.addChildElement("Security", "wsse", WSSE_NS);
            SOAPElement timestamp = security.addChildElement("Timestamp", "wsu", WSU_NS);
            
            String messageId = UUID.randomUUID().toString();
            timestamp.addAttribute(new QName(WSU_NS, "Id", "wsu"), "TS-" + messageId);
            
            SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
            dateFormat.setTimeZone(TimeZone.getTimeZone("UTC"));
            
            Date now = new Date();
            Date expires = new Date(now.getTime() + TIMESTAMP_VALIDITY_MS);
            
            SOAPElement created = timestamp.addChildElement("Created", "wsu", WSU_NS);
            created.addTextNode(dateFormat.format(now));
            
            SOAPElement expiresElement = timestamp.addChildElement("Expires", "wsu", WSU_NS);
            expiresElement.addTextNode(dateFormat.format(expires));
            
            message.saveChanges();
            return true;
            
        } catch (Exception e) {
            throw new RuntimeException("Error adding timestamp to outbound message", e);
        }
    }
    
    private boolean handleInbound(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();
            
            if (header == null) {
                throw new SecurityException("Missing SOAP header");
            }
            
            Iterator<?> securityHeaders = header.getChildElements(
                new QName(WSSE_NS, "Security", "wsse"));
            
            if (!securityHeaders.hasNext()) {
                throw new SecurityException("Missing WS-Security header");
            }
            
            SOAPElement security = (SOAPElement) securityHeaders.next();
            Iterator<?> timestamps = security.getChildElements(
                new QName(WSU_NS, "Timestamp", "wsu"));
            
            if (!timestamps.hasNext()) {
                throw new SecurityException("Missing Timestamp in Security header");
            }
            
            SOAPElement timestamp = (SOAPElement) timestamps.next();
            String timestampId = timestamp.getAttributeValue(new QName(WSU_NS, "Id", "wsu"));
            
            if (timestampId != null && !processedMessageIds.add(timestampId)) {
                throw new SecurityException("Replay attack detected: Message ID already processed");
            }
            
            Iterator<?> createdElements = timestamp.getChildElements(
                new QName(WSU_NS, "Created", "wsu"));
            Iterator<?> expiresElements = timestamp.getChildElements(
                new QName(WSU_NS, "Expires", "wsu"));
            
            if (!createdElements.hasNext() || !expiresElements.hasNext()) {
                throw new SecurityException("Timestamp must contain Created and Expires elements");
            }
            
            SOAPElement created = (SOAPElement) createdElements.next();
            SOAPElement expires = (SOAPElement) expiresElements.next();
            
            SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
            dateFormat.setTimeZone(TimeZone.getTimeZone("UTC"));
            
            Date createdDate = dateFormat.parse(created.getTextContent());
            Date expiresDate = dateFormat.parse(expires.getTextContent());
            Date now = new Date();
            
            if (now.before(createdDate)) {
                throw new SecurityException("Message timestamp is in the future");
            }
            
            if (now.after(expiresDate)) {
                throw new SecurityException("Message timestamp has expired");
            }
            
            if (expiresDate.getTime() - createdDate.getTime() > TIMESTAMP_VALIDITY_MS) {
                throw new SecurityException("Timestamp validity period exceeds maximum allowed");
            }
            
            cleanupOldMessageIds();
            
            return true;
            
        } catch (SecurityException e) {
            throw e;
        } catch (Exception e) {
            throw new RuntimeException("Error validating timestamp in inbound message", e);
        }
    }
    
    private void cleanupOldMessageIds() {
        if (processedMessageIds.size() > 10000) {
            Iterator<String> iterator = processedMessageIds.iterator();
            int toRemove = processedMessageIds.size() / 2;
            for (int i = 0; i < toRemove && iterator.hasNext(); i++) {
                iterator.next();
                iterator.remove();
            }
        }
    }
    
    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }
    
    @Override
    public void close(MessageContext context) {
    }
    
    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSSE_NS, "Security"));
        return headers;
    }
}